module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR, NEG_DIVISOR;
    reg [3:0] cnt;
    reg start_cnt;
    reg [15:0] result_reg;
    reg SUB;

    always @(*) begin
        if (opn_valid && ~res_valid) begin
            dividend_reg = dividend;
            divisor_reg = divisor;
            SR = {dividend_reg, 8'b0};
            NEG_DIVISOR = ~{1'b0, divisor_reg} + 1'b1;
            cnt = 4'b0001;
            start_cnt = 1'b1;
            result_reg = 16'b0;
        end
        else begin
            dividend_reg = dividend_reg;
            divisor_reg = divisor_reg;
            SR = SR;
            NEG_DIVISOR = NEG_DIVISOR;
            cnt = cnt;
            start_cnt = start_cnt;
            result_reg = result_reg;
        end
    end

    always @(*) begin
        if (start_cnt) begin
            if (cnt[3]) begin
                cnt = 4'b0001;
                start_cnt = 1'b0;
                result_reg = SR[15:8];
            end
            else begin
                cnt = cnt + 1'b1;
                start_cnt = 1'b1;
                result_reg = result_reg;
            end
            if (sign && dividend[7]) SR = {dividend_reg, 8'b0};
        end
        else begin
            cnt = cnt;
            start_cnt = start_cnt;
            result_reg = result_reg;
            if (sign && dividend[7]) SR = {dividend_reg, 8'b0};
            else SR = SR;
        end
    end

    always @(*) begin
        if (start_cnt) begin
            SUB = SR[15:8] + NEG_DIVISOR;
        end
        else begin
            SUB = {8'b0, SR[7:0], 1'b0} + NEG_DIVISOR;
        end
    end

    always @(*) begin
        if (start_cnt) begin
            SR = {SR[14:0], 1'b0};
        end
        else begin
            if (sign && dividend[7]) SR = {dividend_reg, 8'b0};
            else SR = SR;
        end
    end

    always @(*) begin
        if (cnt[3]) begin
            if (sign && dividend[7]) result_reg = ~SR[15:8] + 1'b1;
            else result_reg = SR[15:8];
        end
        else result_reg = result_reg;
    end

    assign res_valid = (cnt[3]) ? 1'b1 : 1'b0;
    assign result = result_reg;

endmodule
